const source = $('When Executed by Another Workflow').item.json;
const raw = source['18. table_data: Все строки из табличной части счета'];
const rows = JSON.parse(raw);

// справочник Ref_Key → Description
const units = [
  { "Ref_Key": "bb3a0961-e627-11ec-a0ac-1c1bb55b5d00", "Description": "кг" },
  { "Ref_Key": "bb3a0962-e627-11ec-a0ac-1c1bb55b5d00", "Description": "шт" },
  { "Ref_Key": "c9bbfd65-e627-11ec-a0ac-1c1bb55b5d00", "Description": "км" },
  { "Ref_Key": "c9bbfd66-e627-11ec-a0ac-1c1bb55b5d00", "Description": "л" },
  { "Ref_Key": "c9bbfd67-e627-11ec-a0ac-1c1bb55b5d00", "Description": "м" },
  { "Ref_Key": "c9bbfd68-e627-11ec-a0ac-1c1bb55b5d00", "Description": "м2" },
  { "Ref_Key": "c9bbfd69-e627-11ec-a0ac-1c1bb55b5d00", "Description": "м3" },
  { "Ref_Key": "c9bbfd6a-e627-11ec-a0ac-1c1bb55b5d00", "Description": "т" },
  { "Ref_Key": "c9bbfd6b-e627-11ec-a0ac-1c1bb55b5d00", "Description": "ч" },
  { "Ref_Key": "c234b7fb-5fe7-11ed-a0d1-1c1bb55b5d00", "Description": "Услуга" },
  { "Ref_Key": "5b9d931e-e4e1-11ed-a0f9-1c1bb55b5d00", "Description": "тг" }
];

return rows.map(row => {
  const unitText = row["units of measure"];   // например: "услуга"
  // ищем без учета регистра
  const found = units.find(u => u.Description.toLowerCase() === unitText.toLowerCase());

  return {
    json: {
      ...row,
      unitRef_Key: found ? found.Ref_Key : null
    }
  };
});

const outputItems = [];

for (const item of items) {
  const inputItem = item.json;
  const quantity = inputItem.quantity || 1;

  const baseDescription = inputItem.description;
  const totalSum = inputItem.sum || 0;
  const pricePerUnit = totalSum / quantity;

  if (quantity <= 1) {
    outputItems.push({ json: inputItem });
    continue;
  }

  for (let i = 1; i <= quantity; i++) {
    const newItem = { ...inputItem };
    newItem.description = `${baseDescription}`;
    newItem.quantity = 1;
    newItem.sum = pricePerUnit;
    newItem.unit_price = pricePerUnit;

    outputItems.push({ json: newItem });
  }
}

return outputItems;

const buf = $('create_buffer').item.json || {};
const contractTextRaw = String(buf.contract ?? '').trim();

function isNoContract(text) {
  if (!text) return true;
  let s = text
    .toLowerCase()
    .replace(/[«»"“”'`]/g, '')
    .replace(/[-–—]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  const exactBads = new Set(['без договора','нет договора','б/д','нет','—','-','— —','n/a','na']);
  if (exactBads.has(s)) return true;
  const patterns = [
    /\bбез\s+догов[оа]ра\b/,
    /\bнет\s+догов[оа]ра\b/,
    /\bдогов[оа]р\s*не\s*требуетс[яь]\b/,
    /\bне\s*заключ[её]н\b/,
    /\bотсутствует\b/,
    /^б\/д$/
  ];
  return patterns.some(rx => rx.test(s));
}

const contractIsMissing = isNoContract(contractTextRaw);
const contractText = contractIsMissing ? '' : contractTextRaw;

const contrList = Array.isArray($json.value) ? $json.value : [];
const hasContragent = contrList.length > 0;

const MAIN_ZERO = '00000000-0000-0000-0000-000000000000';

const contragent = hasContragent ? contrList[0] : {};

const mainContractKey = hasContragent
  ? (contragent['ОсновнойДоговорКонтрагента_Key'] ?? MAIN_ZERO)
  : MAIN_ZERO;

const contragentRefKey = contragent.Ref_Key || MAIN_ZERO;

const hasMainContract = hasContragent && mainContractKey !== MAIN_ZERO;
const hasContractText = contractText.length > 0;

return [{
  json: {
    bin: $('baseUrl').first().json.bin,
    n_income: $('baseUrl').first().json.N_income,
    Ref_Key: contragentRefKey,
    hasContragent,
    needIikCheck: hasContragent,
    needContractCompare: hasContragent && hasMainContract && hasContractText,
    needContractCreateAsMain: hasContragent && !hasMainContract && hasContractText,
    proceedWithoutContract: hasContragent && !hasContractText,
    contractText,
    mainContractKey: hasMainContract ? mainContractKey : null
  }
}];

const approveList = $items('When Executed by Another Workflow');
const baseList = $items('baseUrl');
const bufList = $items('create_buffer');

const base = baseList[baseList.length - 1]?.json ?? {}; 
const buf = bufList[$itemIndex]?.json ?? {}; 

function isExec(name){ try { return $(name).isExecuted; } catch { return false; } }
function firstJson(name){ try { return $(name).first().json; } catch { return undefined; } }

function isZeroLike(v) {
  if (v === undefined || v === null) return true;
  const s = String(v).trim();
  if (!s) return true;
  const num = Number(s.replace(',', '.'));
  if (!Number.isFinite(num)) return true;
  return num === 0;
}
const vatZero = isZeroLike(buf.vat);
const vatKey = vatZero ? base?.['Ref_СтавкаНДС_безНДС'] : base?.['Ref_СтавкаНДС_12'];
const vatOn = !vatZero;

// 1. Определение ключей контрагента и договора
const contractorKey = isExec('Add Contragent')
  ? firstJson('Add Contragent')?.Ref_Key
  : $json.Ref_Key;

const contractKey = isExec('Get Contract')
  ? firstJson('Get Contract')?.Ref_Key
  : (isExec('Add Contract') ? firstJson('Add Contract')?.Ref_Key : null);


// 2. Композитный поиск данных счета в узле "Проверяем согласование"
const currentBin = $json.bin;
const currentInvoiceNumber = $json.n_income;

const invoiceNumberKey = '16. invoice_number: Номер счета на оплату';
const binKey = '1. vendor_bin: БИН поставщика';

const approveItem = approveList.find(item => 
    item.json[invoiceNumberKey] === currentInvoiceNumber &&
    item.json[binKey] === currentBin
);

const approve = approveItem?.json ?? {};


// 3. Сборка финальной шапки
const invoiceHeader = {
  Date: new Date().toISOString(),
  Контрагент_Key: contractorKey,
  ВалютаДокумента_Key: 'b3b3297a-e627-11ec-a0ac-1c1bb55b5d00',
  Комментарий: String(approve['19. invoice_name'] ?? ''),
  КодНазначенияПлатежа: String(approve['5. vendor_knp: КНП поставщика'] ?? ''),
  НомерВходящегоДокумента: String(approve[invoiceNumberKey] ?? ''),
  ДатаВходящегоДокумента: new Date(approve['17. invoice_date: Дата счета'] || Date.now()).toISOString(),
  УчитыватьНДС: vatOn,
  ...(contractKey ? { ДоговорКонтрагента_Key: contractKey } : {})
};

return [{ json: { ...$json, vatKey, vatOn, invoiceHeader } }];

